import{_ as a,a as e}from"./chunks/查询额度成功.wz9SQqrH.js";import{_ as d,o,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"pCloud Channel ထည့်သွင်းခြင်း","description":"","frontmatter":{},"headers":[],"relativePath":"my/upload/pcloud.md","filePath":"my/upload/pcloud.md","lastUpdated":1781962217000}'),n={name:"my/upload/pcloud.md"};function i(c,t,p,r,h,u){return o(),l("div",null,[...t[0]||(t[0]=[s('<h1 id="pcloud-channel-ထည့်သွင်းခြင်း" tabindex="-1">pCloud Channel ထည့်သွင်းခြင်း <a class="header-anchor" href="#pcloud-channel-ထည့်သွင်းခြင်း" aria-label="Permalink to &quot;pCloud Channel ထည့်သွင်းခြင်း&quot;">​</a></h1><h2 id="ဘယ်အချိန်မှာ-သင့်တော်လဲ" tabindex="-1">ဘယ်အချိန်မှာ သင့်တော်လဲ <a class="header-anchor" href="#ဘယ်အချိန်မှာ-သင့်တော်လဲ" aria-label="Permalink to &quot;ဘယ်အချိန်မှာ သင့်တော်လဲ&quot;">​</a></h2><ul><li>pCloud account ရှိပြီး ImgBed images တွေကို pCloud ထဲသိမ်းချင်လျှင်။</li><li>pCloud account email နဲ့ password ကို channel credentials အဖြစ်သုံးတာအဆင်ပြေလျှင်။</li></ul><h2 id="စမလုပ်ခင်-လိုအပ်တာတွေ" tabindex="-1">စမလုပ်ခင် လိုအပ်တာတွေ <a class="header-anchor" href="#စမလုပ်ခင်-လိုအပ်တာတွေ" aria-label="Permalink to &quot;စမလုပ်ခင် လိုအပ်တာတွေ&quot;">​</a></h2><table tabindex="0"><thead><tr><th>လိုအပ်ချက်</th><th>ဘာကြောင့်လိုလဲ</th></tr></thead><tbody><tr><td>pCloud account email</td><td>pCloud API ကို sign in ဝင်ရန်</td></tr><tr><td>pCloud password</td><td>pCloud API ကို sign in ဝင်ရန်</td></tr><tr><td>API host</td><td>default က <code>api.pcloud.com</code>။ EU accounts အတွက် <code>eapi.pcloud.com</code> သုံးနိုင်သည်။</td></tr><tr><td>Storage directory</td><td>files သိမ်းမယ့်နေရာ။ default က <code>imgbed</code>။</td></tr></tbody></table><h2 id="ဘယ်နေရာမှာ-ထည့်မလဲ" tabindex="-1">ဘယ်နေရာမှာ ထည့်မလဲ <a class="header-anchor" href="#ဘယ်နေရာမှာ-ထည့်မလဲ" aria-label="Permalink to &quot;ဘယ်နေရာမှာ ထည့်မလဲ&quot;">​</a></h2><ol><li>System Settings ကိုဖွင့်ပါ။</li><li>Upload Settings ကိုဖွင့်ပါ။</li><li>ညာဘက်အပေါ်ထောင့်က <code>Add Channel</code> ကိုနှိပ်ပါ။</li><li><code>pCloud</code> ကိုရွေးပါ။</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Purpose</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>ဒီ pCloud channel ကိုသိနိုင်မယ့်အမည်၊ ဥပမာ <code>Personal pCloud</code></td><td>Yes</td></tr><tr><td>Account email</td><td>သင့် pCloud login email</td><td>Yes</td></tr><tr><td>Password</td><td>သင့် pCloud password</td><td>Yes</td></tr><tr><td>API host</td><td>pCloud API host။ default က <code>api.pcloud.com</code>။</td><td>No</td></tr><tr><td>Storage directory</td><td>files သိမ်းမယ့် directory။ default က <code>imgbed</code>။</td><td>No</td></tr></tbody></table><p>account region အလိုက် API host ရွေးပါ:</p><table tabindex="0"><thead><tr><th>Account Region</th><th>API Host</th></tr></thead><tbody><tr><td>Default / US</td><td><code>api.pcloud.com</code></td></tr><tr><td>Europe</td><td><code>eapi.pcloud.com</code></td></tr></tbody></table><h2 id="setup-steps" tabindex="-1">Setup Steps <a class="header-anchor" href="#setup-steps" aria-label="Permalink to &quot;Setup Steps&quot;">​</a></h2><ol><li>Upload Settings ကိုဖွင့်ပါ။</li><li><code>Add Channel</code> ကိုနှိပ်ပါ။</li><li><code>pCloud</code> ကိုရွေးပါ။</li><li>မှတ်မိလွယ်တဲ့ channel name ထည့်ပါ။</li><li>pCloud account email ထည့်ပါ။</li><li>pCloud password ထည့်ပါ။</li><li>API host ကို <code>api.pcloud.com</code> အတိုင်းထားပါ၊ EU account ဖြစ်လျှင် <code>eapi.pcloud.com</code> သုံးပါ။</li><li>storage directory ကို <code>imgbed</code> အတိုင်းထားပါ၊ သို့မဟုတ် ကိုယ်နှစ်သက်တဲ့ folder ပြောင်းထည့်ပါ။</li><li>channel ကို save လုပ်ပါ။</li></ol><p><img src="'+a+'" alt="Configure channel" loading="lazy"></p><h2 id="စစ်ဆေးနည်း" tabindex="-1">စစ်ဆေးနည်း <a class="header-anchor" href="#စစ်ဆေးနည်း" aria-label="Permalink to &quot;စစ်ဆေးနည်း&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Expected Result</th></tr></thead><tbody><tr><td>Channel card</td><td>Save ပြီးနောက် pCloud channel card ပေါ်လာရပါမယ်။</td></tr><tr><td>Channel switch</td><td>card ပေါ်က switch က enabled ဖြစ်ရပါမယ်။</td></tr><tr><td>Email display</td><td>card က connected pCloud email ကိုပြရပါမယ်။</td></tr><tr><td>Quota query</td><td>query အောင်မြင်ပြီးနောက် used နဲ့ total capacity ပြရပါမယ်။</td></tr><tr><td>Upload test</td><td>test image က configured pCloud storage directory ထဲပေါ်လာရပါမယ်။</td></tr></tbody></table><p><img src="'+e+`" alt="Quota query success" loading="lazy"></p><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="oauth2-မသုံးတာဘာကြောင့်လဲ" tabindex="-1">OAuth2 မသုံးတာဘာကြောင့်လဲ? <a class="header-anchor" href="#oauth2-မသုံးတာဘာကြောင့်လဲ" aria-label="Permalink to &quot;OAuth2 မသုံးတာဘာကြောင့်လဲ?&quot;">​</a></h3><p>pCloud OAuth2 က default အနေနဲ့ self-service မဟုတ်ပါ။ enable လုပ်ချင်ရင် pCloud ကို email ပို့ပြီးတောင်းရပါတယ်။</p><p>လက်ရှိ pCloud OAuth2 flow က ImgBed လိုအပ်တဲ့ short-lived upload link workflow ကိုလည်းမထောက်ပံ့ပါ။ ဒါကြောင့် ဒီ channel က account email/password login ကိုသုံးပါတယ်။</p><h3 id="ဘယ်-api-host-သုံးရမလဲ" tabindex="-1">ဘယ် API Host သုံးရမလဲ? <a class="header-anchor" href="#ဘယ်-api-host-သုံးရမလဲ" aria-label="Permalink to &quot;ဘယ် API Host သုံးရမလဲ?&quot;">​</a></h3><p>Default:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>api.pcloud.com</span></span></code></pre></div><p>EU accounts အတွက်:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>eapi.pcloud.com</span></span></code></pre></div><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pCloud email နဲ့ password ပြင်ဆင်ပါ</span></span>
<span class="line"><span>-&gt; Upload Settings ဖွင့်ပါ</span></span>
<span class="line"><span>-&gt; Add Channel</span></span>
<span class="line"><span>-&gt; pCloud ရွေးပါ</span></span>
<span class="line"><span>-&gt; channel name / email / password ဖြည့်ပါ</span></span>
<span class="line"><span>-&gt; account က Europe မဟုတ်လျှင် API host ကို api.pcloud.com ထားပါ</span></span>
<span class="line"><span>-&gt; အခြား folder မလိုလျှင် storage directory ကို imgbed ထားပါ</span></span>
<span class="line"><span>-&gt; Save</span></span>
<span class="line"><span>-&gt; quota query</span></span>
<span class="line"><span>-&gt; test image upload</span></span></code></pre></div>`,28)])])}const C=d(n,[["render",i]]);export{g as __pageData,C as default};
